all_items = batch_1 + batch_2 + batch_3

master_list = []

for item in all_items:
    safe_name = item['اسم الصنف'].replace('/', '-').replace('\\', '-')
    filename = f"{item['م']:02}_{safe_name}.json"
    filepath = os.path.join(items_dir, filename)
    
    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(item, f, ensure_ascii=False, indent=4)
        
    master_list.append({
        'م': item['م'],
        'الاسم': item['اسم الصنف'],
        'الرصيد': item['الرصيد'],
        'سعر البيع': item['البيع'],
        'الملف': f"Dashboard_Items/{filename}"
    })

# إنشاء ملف مدير الأصناف الرئيسي
with open(os.path.join(base_dir, 'مدير_الأصناف_الرئيسي.md'), 'w', encoding='utf-8') as f:
    f.write("# مدير الأصناف والمخزون - شركة NetLink\n\n")
    f.write("جدول شامل لمتابعة المخزون والأسعار لكافة الأصناف (تم استخراجه من الصور بدقة).\n\n")
    f.write("| م | اسم الصنف | الرصيد الحالي | سعر البيع | رابط ملف التحرير |\n")
    f.write("| :--- | :--- | :--- | :--- | :--- |\n")
    for item in master_list:
        abs_path = os.path.abspath(os.path.join(base_dir, item['الملف'])).replace('\\', '/')
        f.write(f"| {item['م']} | {item['الاسم']} | {item['الرصيد']} | {item['سعر البيع']} ₪ | [فتح ملف التعديل](file:///{abs_path}) |\n")

print(f"SUCCESS: Generated {len(all_items)} item files and index.")
